import { render, screen, within } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { describe, expect, it, vi } from "vitest";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "./DropdownMenu";

function DropdownExample({
  onArchive = vi.fn(),
  onRename = vi.fn(),
  onSelect = vi.fn(),
}: {
  onArchive?: () => void;
  onRename?: () => void;
  onSelect?: () => void;
}) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger>Actions</DropdownMenuTrigger>
      <DropdownMenuContent aria-label="Project actions">
        <DropdownMenuItem onClick={onSelect}>Duplicate</DropdownMenuItem>
        <DropdownMenuItem disabled onClick={onArchive}>
          Archive
        </DropdownMenuItem>
        <DropdownMenuItem onClick={onRename}>Rename</DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

describe("DropdownMenu", () => {
  it("connects trigger and menu with ARIA and closes on item select", async () => {
    const user = userEvent.setup();
    const onSelect = vi.fn();

    render(<DropdownExample onSelect={onSelect} />);

    const trigger = screen.getByRole("button", { name: "Actions" });
    expect(trigger).toHaveAttribute("aria-haspopup", "menu");
    expect(trigger).toHaveAttribute("aria-expanded", "false");
    expect(trigger).not.toHaveAttribute("aria-controls");

    await user.click(trigger);

    const menu = await screen.findByRole("menu", {
      name: "Project actions",
    });
    expect(trigger).toHaveAttribute("aria-expanded", "true");
    expect(trigger).toHaveAttribute("aria-controls", menu.id);
    expect(within(menu).getByRole("menuitem", { name: "Archive" })).toBeDisabled();

    await user.click(within(menu).getByRole("menuitem", { name: "Duplicate" }));

    expect(onSelect).toHaveBeenCalledTimes(1);
    expect(screen.queryByRole("menu")).not.toBeInTheDocument();
    expect(trigger).toHaveFocus();
    expect(trigger).toHaveAttribute("aria-expanded", "false");
    expect(trigger).not.toHaveAttribute("aria-controls");
  });

  it("opens from keyboard activation and closes on Escape with focus returned", async () => {
    const user = userEvent.setup();

    render(<DropdownExample />);

    const trigger = screen.getByRole("button", { name: "Actions" });
    trigger.focus();

    await user.keyboard("{Enter}");

    const menu = await screen.findByRole("menu");
    expect(within(menu).getByRole("menuitem", { name: "Duplicate" }))
      .toHaveFocus();

    await user.keyboard("{Escape}");

    expect(screen.queryByRole("menu")).not.toBeInTheDocument();
    expect(trigger).toHaveFocus();
    expect(trigger).toHaveAttribute("aria-expanded", "false");
    expect(trigger).not.toHaveAttribute("aria-controls");
  });

  it("moves through enabled items with arrow, Home, and End keys", async () => {
    const user = userEvent.setup();
    const onRename = vi.fn();

    render(<DropdownExample onRename={onRename} />);

    const trigger = screen.getByRole("button", { name: "Actions" });
    trigger.focus();

    await user.keyboard("{ArrowDown}");

    const menu = await screen.findByRole("menu");
    const duplicateItem = within(menu).getByRole("menuitem", {
      name: "Duplicate",
    });
    const archiveItem = within(menu).getByRole("menuitem", {
      name: "Archive",
    });
    const renameItem = within(menu).getByRole("menuitem", {
      name: "Rename",
    });

    expect(duplicateItem).toHaveFocus();
    expect(archiveItem).toBeDisabled();

    await user.keyboard("{ArrowDown}");
    expect(renameItem).toHaveFocus();

    await user.keyboard("{ArrowDown}");
    expect(duplicateItem).toHaveFocus();

    await user.keyboard("{ArrowUp}");
    expect(renameItem).toHaveFocus();

    await user.keyboard("{Home}");
    expect(duplicateItem).toHaveFocus();

    await user.keyboard("{End}");
    expect(renameItem).toHaveFocus();

    await user.keyboard("{Enter}");

    expect(onRename).toHaveBeenCalledTimes(1);
    expect(screen.queryByRole("menu")).not.toBeInTheDocument();
    expect(trigger).toHaveFocus();
  });

  it("keeps disabled menu items inert", async () => {
    const user = userEvent.setup();
    const onArchive = vi.fn();

    render(<DropdownExample onArchive={onArchive} />);

    await user.click(screen.getByRole("button", { name: "Actions" }));

    const menu = await screen.findByRole("menu");
    const archiveItem = within(menu).getByRole("menuitem", {
      name: "Archive",
    });

    expect(archiveItem).toBeDisabled();

    await user.click(archiveItem);

    expect(onArchive).not.toHaveBeenCalled();
    expect(screen.getByRole("menu")).toBeInTheDocument();
  });
});

"use client";

import type { HTMLAttributes } from "react";
import { forwardRef, useEffect, useId, useRef, useState } from "react";
import { cn, composeRefs, swirskiAttrs } from "../../system";
import { DropdownMenuContext } from "./DropdownMenuContext";
import type {
  DropdownMenuFocusIntent,
  DropdownMenuSize,
  DropdownMenuTone,
  DropdownMenuVariant,
} from "./dropdown-menu-types";

export { DropdownMenuContent } from "./DropdownMenuContent";
export type { DropdownMenuContentProps } from "./DropdownMenuContent";
export { DropdownMenuItem } from "./DropdownMenuItem";
export type { DropdownMenuItemProps } from "./DropdownMenuItem";
export { DropdownMenuTrigger } from "./DropdownMenuTrigger";
export type { DropdownMenuTriggerProps } from "./DropdownMenuTrigger";
export type {
  DropdownMenuSize,
  DropdownMenuTone,
  DropdownMenuVariant,
} from "./dropdown-menu-types";

export type DropdownMenuProps = {
  variant?: DropdownMenuVariant;
  size?: DropdownMenuSize;
  tone?: DropdownMenuTone;
} & HTMLAttributes<HTMLDivElement>;

export const DropdownMenu = forwardRef<HTMLDivElement, DropdownMenuProps>(
  function DropdownMenu(
    {
      children,
      className,
      variant = "default",
      size = "md",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const contentId = useId();
    const rootRef = useRef<HTMLDivElement>(null);
    const triggerRef = useRef<HTMLButtonElement>(null);
    const contentRef = useRef<HTMLDivElement>(null);
    const focusIntentRef = useRef<DropdownMenuFocusIntent>(null);
    const [open, setOpen] = useState(false);

    useEffect(() => {
      if (!open) {
        return;
      }

      const handlePointerDown = (event: PointerEvent) => {
        const target = event.target as Node;

        if (
          !rootRef.current?.contains(target) &&
          !contentRef.current?.contains(target)
        ) {
          setOpen(false);
        }
      };

      const handleKeyDown = (event: KeyboardEvent) => {
        if (event.key === "Escape") {
          setOpen(false);
        }
      };

      window.addEventListener("pointerdown", handlePointerDown);
      window.addEventListener("keydown", handleKeyDown);

      return () => {
        window.removeEventListener("pointerdown", handlePointerDown);
        window.removeEventListener("keydown", handleKeyDown);
      };
    }, [open]);

    return (
      <DropdownMenuContext.Provider
        value={{
          open,
          setOpen,
          rootRef,
          triggerRef,
          contentRef,
          contentId,
          focusIntentRef,
        }}
      >
        <div
          ref={composeRefs(rootRef, ref)}
          className={cn("relative w-fit", className)}
          {...swirskiAttrs("dropdown-menu", { size, tone, variant })}
          {...props}
        >
          {children}
        </div>
      </DropdownMenuContext.Provider>
    );
  },
);

DropdownMenu.displayName = "DropdownMenu";

export type DropdownMenuSeparatorProps = {
  variant?: DropdownMenuVariant;
  size?: DropdownMenuSize;
  tone?: DropdownMenuTone;
} & HTMLAttributes<HTMLDivElement>;

export const DropdownMenuSeparator = forwardRef<
  HTMLDivElement,
  DropdownMenuSeparatorProps
>(function DropdownMenuSeparator(
  { className, variant = "default", size = "md", tone = "default", ...props },
  ref,
) {
  return (
    <div
      ref={ref}
      className={cn("my-1 border-t-4 border-black", className)}
      {...swirskiAttrs("dropdown-menu-separator", { size, tone, variant })}
      {...props}
    />
  );
});

DropdownMenuSeparator.displayName = "DropdownMenuSeparator";

"use client";

import type {
  HTMLAttributes,
  KeyboardEvent as ReactKeyboardEvent,
} from "react";
import { forwardRef, useEffect } from "react";
import { createPortal } from "react-dom";
import { cn, composeRefs, swirskiAttrs } from "../../system";
import { useFloatingPosition } from "../../system/floating";
import { usePortalRoot } from "../../hooks/use-portal-root/usePortalRoot";
import { useDropdownMenu } from "./DropdownMenuContext";
import type {
  DropdownMenuSize,
  DropdownMenuTone,
  DropdownMenuVariant,
} from "./dropdown-menu-types";
import { focusMenuItem, getCurrentMenuItemIndex } from "./dropdown-menu-utils";

export type DropdownMenuContentProps = HTMLAttributes<HTMLDivElement> & {
  align?: "start" | "end";
  variant?: DropdownMenuVariant;
  size?: DropdownMenuSize;
  tone?: DropdownMenuTone;
};

export const DropdownMenuContent = forwardRef<
  HTMLDivElement,
  DropdownMenuContentProps
>(function DropdownMenuContent(
  {
    className,
    align = "start",
    variant = "default",
    size = "md",
    tone = "default",
    onKeyDown,
    style,
    ...props
  },
  ref,
) {
  const {
    contentId,
    contentRef,
    focusIntentRef,
    open,
    rootRef,
    setOpen,
    triggerRef,
  } = useDropdownMenu();
  const portalRoot = usePortalRoot();
  const floatingStyle = useFloatingPosition({
    floatingRef: contentRef,
    open,
    placement: align === "end" ? "bottom-end" : "bottom-start",
    referenceRef: rootRef,
  });

  useEffect(() => {
    if (!open || !contentRef.current || !focusIntentRef.current) {
      return;
    }

    focusMenuItem(
      contentRef.current,
      focusIntentRef.current === "first" ? 0 : -1,
    );
    focusIntentRef.current = null;
  }, [contentRef, focusIntentRef, open]);

  function handleKeyDown(event: ReactKeyboardEvent<HTMLDivElement>) {
    onKeyDown?.(event);

    if (event.defaultPrevented || !contentRef.current) {
      return;
    }

    if (event.key === "ArrowDown") {
      event.preventDefault();
      focusMenuItem(
        contentRef.current,
        getCurrentMenuItemIndex(contentRef.current) + 1,
      );
      return;
    }

    if (event.key === "ArrowUp") {
      event.preventDefault();
      focusMenuItem(
        contentRef.current,
        getCurrentMenuItemIndex(contentRef.current) - 1,
      );
      return;
    }

    if (event.key === "Home") {
      event.preventDefault();
      focusMenuItem(contentRef.current, 0);
      return;
    }

    if (event.key === "End") {
      event.preventDefault();
      focusMenuItem(contentRef.current, -1);
      return;
    }

    if (event.key === "Escape") {
      event.preventDefault();
      setOpen(false);
      triggerRef.current?.focus();
    }
  }

  if (!open || !portalRoot) {
    return null;
  }

  return createPortal(
    <div
      ref={composeRefs(contentRef, ref)}
      className={cn(
        "fixed z-[1000] min-w-48 border-4 border-black bg-white p-1 shadow-[8px_8px_0_#0B0B0C]",
        variant === "compact" && "shadow-[4px_4px_0_#0B0B0C]",
        className,
      )}
      id={contentId}
      onKeyDown={handleKeyDown}
      role="menu"
      {...swirskiAttrs("dropdown-menu-content", { size, tone, variant })}
      style={{
        ...floatingStyle,
        ...style,
      }}
      {...props}
    />,
    portalRoot,
  );
});

DropdownMenuContent.displayName = "DropdownMenuContent";

"use client";

import type { MutableRefObject, RefObject } from "react";
import { createContext, useContext } from "react";
import type { DropdownMenuFocusIntent } from "./dropdown-menu-types";

export type DropdownMenuContextValue = {
  open: boolean;
  setOpen: (open: boolean) => void;
  rootRef: RefObject<HTMLDivElement | null>;
  triggerRef: RefObject<HTMLButtonElement | null>;
  contentRef: RefObject<HTMLDivElement | null>;
  contentId: string;
  focusIntentRef: MutableRefObject<DropdownMenuFocusIntent>;
};

export const DropdownMenuContext =
  createContext<DropdownMenuContextValue | null>(null);

export function useDropdownMenu() {
  const context = useContext(DropdownMenuContext);

  if (!context) {
    throw new Error("DropdownMenu components must be used inside DropdownMenu.");
  }

  return context;
}

"use client";

import type { ButtonHTMLAttributes } from "react";
import { forwardRef } from "react";
import { Slot, cn, swirskiAttrs } from "../../system";
import { useDropdownMenu } from "./DropdownMenuContext";
import type {
  DropdownMenuSize,
  DropdownMenuTone,
  DropdownMenuVariant,
} from "./dropdown-menu-types";
import { itemSizeStyles } from "./dropdown-menu-utils";

export type DropdownMenuItemProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  asChild?: boolean;
  variant?: DropdownMenuVariant;
  size?: DropdownMenuSize;
  tone?: DropdownMenuTone;
  active?: boolean;
};

export const DropdownMenuItem = forwardRef<
  HTMLButtonElement,
  DropdownMenuItemProps
>(function DropdownMenuItem(
  {
    asChild = false,
    className,
    onClick,
    variant = "default",
    size = "md",
    tone = "default",
    active = false,
    ...props
  },
  ref,
) {
  const { setOpen, triggerRef } = useDropdownMenu();
  const Component = asChild ? Slot : "button";

  const baseStyles =
    "block w-full text-left font-black uppercase transition hover:bg-[var(--sw-color-yellow)] focus-visible:bg-[var(--sw-color-yellow)] focus-visible:outline-none disabled:cursor-not-allowed disabled:text-black/35 disabled:hover:bg-transparent";

  return (
    <Component
      ref={ref}
      className={cn(
        baseStyles,
        active && "bg-[var(--sw-color-yellow)]",
        itemSizeStyles[size],
        className,
      )}
      onClick={(event) => {
        onClick?.(event);

        if (!event.defaultPrevented) {
          setOpen(false);
          triggerRef.current?.focus();
        }
      }}
      role="menuitem"
      type={asChild ? undefined : "button"}
      {...swirskiAttrs("dropdown-menu-item", { size, tone, variant })}
      data-active={active ? "" : undefined}
      {...props}
    />
  );
});

DropdownMenuItem.displayName = "DropdownMenuItem";

"use client";

import type { ButtonHTMLAttributes } from "react";
import { forwardRef } from "react";
import {
  Slot,
  cn,
  composeRefs,
  disabledInteractiveStyles,
  focusVisibleStyles,
  swirskiAttrs,
} from "../../system";
import { useDropdownMenu } from "./DropdownMenuContext";
import type {
  DropdownMenuSize,
  DropdownMenuTone,
  DropdownMenuVariant,
} from "./dropdown-menu-types";
import { triggerSizeStyles } from "./dropdown-menu-utils";

export type DropdownMenuTriggerProps =
  ButtonHTMLAttributes<HTMLButtonElement> & {
    asChild?: boolean;
    variant?: DropdownMenuVariant;
    size?: DropdownMenuSize;
    tone?: DropdownMenuTone;
  };

export const DropdownMenuTrigger = forwardRef<
  HTMLButtonElement,
  DropdownMenuTriggerProps
>(function DropdownMenuTrigger(
  {
    asChild = false,
    className,
    variant = "default",
    size = "md",
    tone = "default",
    onClick,
    onKeyDown,
    ...props
  },
  ref,
) {
  const { contentId, focusIntentRef, open, setOpen, triggerRef } =
    useDropdownMenu();
  const Component = asChild ? Slot : "button";

  return (
    <Component
      ref={composeRefs(triggerRef, ref)}
      className={cn(
        "border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] bg-[var(--sw-color-surface)] font-black uppercase shadow-[4px_4px_0_var(--sw-color-shadow)] outline-none transition-all duration-150 hover:translate-x-1 hover:translate-y-1 hover:shadow-none active:translate-x-2 active:translate-y-2 disabled:hover:shadow-[4px_4px_0_var(--sw-color-shadow)]",
        focusVisibleStyles,
        disabledInteractiveStyles,
        triggerSizeStyles[size],
        variant === "compact" && "shadow-none disabled:hover:shadow-none",
        className,
      )}
      onClick={(event) => {
        onClick?.(event);

        if (!event.defaultPrevented) {
          setOpen(!open);
        }
      }}
      onKeyDown={(event) => {
        onKeyDown?.(event);

        if (event.defaultPrevented) {
          return;
        }

        if (
          event.key === "ArrowDown" ||
          event.key === "Enter" ||
          event.key === " "
        ) {
          event.preventDefault();
          focusIntentRef.current = "first";
          setOpen(true);
          return;
        }

        if (event.key === "ArrowUp") {
          event.preventDefault();
          focusIntentRef.current = "last";
          setOpen(true);
        }
      }}
      type={asChild ? undefined : "button"}
      aria-controls={open ? contentId : undefined}
      aria-expanded={open}
      aria-haspopup="menu"
      {...swirskiAttrs("dropdown-menu-trigger", { size, tone, variant })}
      {...props}
    />
  );
});

DropdownMenuTrigger.displayName = "DropdownMenuTrigger";

export type DropdownMenuVariant = "default" | "compact";
export type DropdownMenuSize = "sm" | "md" | "lg";
export type DropdownMenuTone = "default";
export type DropdownMenuFocusIntent = "first" | "last" | null;

import type { DropdownMenuSize } from "./dropdown-menu-types";

export const triggerSizeStyles: Record<DropdownMenuSize, string> = {
  sm: "px-3 py-1.5 text-xs",
  md: "px-4 py-2",
  lg: "px-5 py-3 text-base",
};

export const itemSizeStyles: Record<DropdownMenuSize, string> = {
  sm: "min-h-9 px-2 py-1.5 text-xs",
  md: "min-h-10 px-3 py-2 text-xs",
  lg: "min-h-12 px-4 py-3 text-sm",
};

function getEnabledMenuItems(content: HTMLElement) {
  return Array.from(content.querySelectorAll<HTMLElement>('[role="menuitem"]'))
    .filter((item) => !item.hasAttribute("disabled"))
    .filter((item) => item.getAttribute("aria-disabled") !== "true");
}

export function getCurrentMenuItemIndex(content: HTMLElement) {
  return getEnabledMenuItems(content).findIndex(
    (item) => item === document.activeElement,
  );
}

export function focusMenuItem(content: HTMLElement, index: number) {
  const items = getEnabledMenuItems(content);

  if (!items.length) {
    return;
  }

  const nextIndex = (index + items.length) % items.length;
  items[nextIndex]?.focus();
}

export {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "./DropdownMenu";
export type {
  DropdownMenuContentProps,
  DropdownMenuItemProps,
  DropdownMenuProps,
  DropdownMenuSeparatorProps,
  DropdownMenuSize,
  DropdownMenuTone,
  DropdownMenuTriggerProps,
  DropdownMenuVariant,
} from "./DropdownMenu";
